import { test, expect } from '@playwright/test';

test('visibility assertions', async ({ page }) => {
  await page.goto('https://example.com');

  // Element is visible
  await expect(page.locator('.header')).toBeVisible();

  // Element is hidden
  await expect(page.locator('.modal')).toBeHidden();
  await expect(page.locator('.modal')).not.toBeVisible();

  // Element is attached to DOM (even if not visible)
  await expect(page.locator('.hidden-element')).toBeAttached();

  // Element is enabled/disabled
  await expect(page.locator('button')).toBeEnabled();
  await expect(page.locator('button')).toBeDisabled();

  // Element is editable
  await expect(page.locator('input')).toBeEditable();

  // Element is focused
  await page.focus('input');
  await expect(page.locator('input')).toBeFocused();

  // Checkbox/radio is checked
  await expect(page.locator('#agree')).toBeChecked();
  await expect(page.locator('#disagree')).not.toBeChecked();
});

test('element state', async ({ page }) => {
  await page.goto('https://example.com/form');

  // Empty input
  await expect(page.locator('input')).toBeEmpty();

  // Input has value
  await page.fill('input', 'test');
  await expect(page.locator('input')).not.toBeEmpty();
});

test('text assertions', async ({ page }) => {
  await page.goto('https://example.com');

  // Exact text match
  await expect(page.locator('h1')).toHaveText('Welcome');

  // Partial text match
  await expect(page.locator('h1')).toContainText('Wel');

  // Text with regex
  await expect(page.locator('h1')).toHaveText(/Welcome.*/i);

  // Multiple elements text
  await expect(page.locator('li')).toHaveText([
    'Item 1',
    'Item 2',
    'Item 3'
  ]);

  // Array with regex
  await expect(page.locator('li')).toHaveText([
    /Item \d+/,
    /Item \d+/
  ]);

  // Inner text vs text content
  await expect(page.locator('div')).toHaveText('Visible text');

  // Contains text (substring)
  await expect(page.locator('p')).toContainText('important');
});

test('value assertions', async ({ page }) => {
  await page.goto('https://example.com/form');

  // Input value
  await page.fill('input[name="email"]', 'test@example.com');
  await expect(page.locator('input[name="email"]')).toHaveValue('test@example.com');

  // Value with regex
  await expect(page.locator('input[name="email"]')).toHaveValue(/@example\.com$/);

  // Select value
  await page.selectOption('select', 'option2');
  await expect(page.locator('select')).toHaveValue('option2');
});

test('attribute assertions', async ({ page }) => {
  await page.goto('https://example.com');

  // Has attribute
  await expect(page.locator('a')).toHaveAttribute('href', '/about');

  // Attribute with regex
  await expect(page.locator('a')).toHaveAttribute('href', /\/about/);

  // Has any value for attribute
  await expect(page.locator('img')).toHaveAttribute('src');

  // Multiple attributes
  const link = page.locator('a');
  await expect(link).toHaveAttribute('href', '/about');
  await expect(link).toHaveAttribute('target', '_blank');

  // Class attribute
  await expect(page.locator('button')).toHaveClass('btn btn-primary');
  await expect(page.locator('button')).toHaveClass(/btn-primary/);

  // Has specific class (among others)
  await expect(page.locator('div')).toHaveClass(/active/);

  // ID attribute
  await expect(page.locator('div')).toHaveId('main-content');
});

test('CSS assertions', async ({ page }) => {
  await page.goto('https://example.com');

  // CSS property
  await expect(page.locator('button')).toHaveCSS('color', 'rgb(255, 0, 0)');
  await expect(page.locator('button')).toHaveCSS('font-size', '16px');

  // CSS with regex
  await expect(page.locator('button')).toHaveCSS('background-color', /rgb\(/);

  // Note: CSS values are computed values (e.g., 'red' becomes 'rgb(255, 0, 0)')
});

test('count assertions', async ({ page }) => {
  await page.goto('https://example.com/list');

  // Exact count
  await expect(page.locator('li')).toHaveCount(5);

  // Greater than/less than
  const items = await page.locator('li').count();
  expect(items).toBeGreaterThan(0);
  expect(items).toBeLessThan(10);
  expect(items).toBeGreaterThanOrEqual(5);
  expect(items).toBeLessThanOrEqual(5);

  // No elements
  await expect(page.locator('.error')).toHaveCount(0);

  // At least one element
  const count = await page.locator('button').count();
  expect(count).toBeGreaterThan(0);
});

test('array and collection checks', async ({ page }) => {
  await page.goto('https://example.com/list');

  // Get all text content
  const texts = await page.locator('li').allTextContents();
  expect(texts).toHaveLength(5);
  expect(texts).toContain('Item 1');
  expect(texts).toEqual(['Item 1', 'Item 2', 'Item 3', 'Item 4', 'Item 5']);

  // Check if array contains item
  expect(texts).toContain('Item 3');
  expect(texts).not.toContain('Item 6');
});

test('page assertions', async ({ page }) => {
  await page.goto('https://example.com/about');

  // Page title
  await expect(page).toHaveTitle('About Us');
  await expect(page).toHaveTitle(/About/);

  // Page URL
  await expect(page).toHaveURL('https://example.com/about');
  await expect(page).toHaveURL(/\/about/);

  // URL contains
  await expect(page).toHaveURL(/example/);

  // After navigation
  await page.click('a[href="/contact"]');
  await expect(page).toHaveURL(/\/contact/);
});

test('screenshot comparison', async ({ page }) => {
  await page.goto('https://example.com');

  // Visual regression testing
  await expect(page).toHaveScreenshot('homepage.png');

  // Element screenshot
  await expect(page.locator('.header')).toHaveScreenshot('header.png');

  // With options
  await expect(page).toHaveScreenshot('homepage.png', {
    maxDiffPixels: 100,
    threshold: 0.2
  });
});

test('negative assertions', async ({ page }) => {
  await page.goto('https://example.com');

  // Not visible
  await expect(page.locator('.modal')).not.toBeVisible();

  // Does not have text
  await expect(page.locator('h1')).not.toHaveText('Wrong text');

  // Does not have class
  await expect(page.locator('button')).not.toHaveClass('disabled');

  // URL does not match
  await expect(page).not.toHaveURL(/\/admin/);

  // Element not present
  await expect(page.locator('.error-message')).not.toBeAttached();

  // Count is not
  await expect(page.locator('li')).not.toHaveCount(0);
});

test('soft assertions', async ({ page }) => {
  await page.goto('https://example.com');

  // Regular assertion - test stops here if it fails
  await expect(page.locator('h1')).toBeVisible();

  // Soft assertions - test continues even if they fail
  await expect.soft(page.locator('h1')).toHaveText('Welcome');
  await expect.soft(page.locator('.subtitle')).toBeVisible();
  await expect.soft(page.locator('button')).toHaveText('Click Me');

  // All soft assertions are reported at the end
  // Test fails if any soft assertion failed

  // Use case: Check multiple things on a page
  await expect.soft(page.locator('.header')).toBeVisible();
  await expect.soft(page.locator('.footer')).toBeVisible();
  await expect.soft(page.locator('.sidebar')).toBeVisible();
  await expect.soft(page.locator('.content')).toBeVisible();
});

test('when to use soft assertions', async ({ page }) => {
  await page.goto('https://example.com/form');

  // Fill form
  await page.fill('#email', 'invalid-email');
  await page.fill('#password', '123');
  await page.click('#submit');

  // Check all validation messages (don't stop at first failure)
  await expect.soft(page.locator('.email-error')).toBeVisible();
  await expect.soft(page.locator('.password-error')).toBeVisible();
  await expect.soft(page.locator('.terms-error')).toBeVisible();

  // Take screenshot of all errors
  await page.screenshot({ path: 'all-errors.png' });
});

test('custom timeout', async ({ page }) => {
  await page.goto('https://example.com');

  // Default timeout is 5 seconds
  await expect(page.locator('h1')).toBeVisible();

  // Custom timeout for slow operations
  await expect(page.locator('.slow-loading')).toBeVisible({ timeout: 10000 });

  // Short timeout for elements that should appear quickly
  await expect(page.locator('.instant')).toBeVisible({ timeout: 1000 });
});

test('custom error messages', async ({ page }) => {
  await page.goto('https://example.com');

  // Add context to failures
  await expect(page.locator('h1'), 'Header should be visible on homepage').toBeVisible();

  await expect(
    page.locator('.user-name'),
    'User name should be displayed after login'
  ).toHaveText('John Doe');

  // Helpful for debugging when tests fail
});

test('polling assertions', async ({ page }) => {
  await page.goto('https://example.com');

  // Wait for condition with custom check
  await expect.poll(async () => {
    const count = await page.locator('li').count();
    return count;
  }).toBe(5);

  // Wait for value to change
  await expect.poll(async () => {
    return await page.locator('.counter').textContent();
  }).toBe('10');

  // With custom interval and timeout
  await expect.poll(async () => {
    return await page.locator('.status').textContent();
  }, {
    intervals: [100, 250, 500],
    timeout: 10000
  }).toBe('Complete');
});

